#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;


vec3 noiseVal =lum (texture(sampler_noise_lq, corr*vUv*.02+ .1*rand_frame));

vec2 k1 = vec2((vUv.x), (vUv.y));

vec3 ret1 = GetBlur1(vUv) ;

float k2 = (20*vUv)%2;

vec2 zz = vUv.xy * uTexSize.xy *.08;
float h1 = (tan(zz.x));
float h2 = (tan(zz.y));

vUv.xy -= vec2(h1,h2)*uTexSize.zw * audioHigh * 3;


vec3 crisp = texture(sampler_main,vUv) + noiseVal/30;

crisp = mix(crisp, 1-crisp.zyx, 0.01);

 ret = crisp -.03 - 0.2*pow(1-vRadius,18*(audioHigh * 5));
ret += (ret * (uRms * .001));
//ret *= audioLow * 2;
ret += (ret * (audioHigh * .025));
ret += .001;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;

vec2 rotate_uv = 0.5-uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2)*0.667;
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.38, vec2(q11,q12));
vUv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ))*0.9;
d = uTexSize.zw*4;
dx = GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv + vec2(-1,0)*d);
dy = GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv + vec2(0,-1)*d);
vec2 uv1 = fract(vUv + vec2(dx.z,dy.z)*1.6);
vec2 uv_swimmer = clamp01(0.5 + (vUv-0.5)+vec2(q19,q20)*vec2(-1,1));
d = uTexSize.zw*3;
dx = GetBlur1(uv_swimmer + vec2(1,0)*d) - GetBlur1(uv_swimmer + vec2(-1,0)*d);
dy = GetBlur1(uv_swimmer + vec2(0,1)*d) - GetBlur1(uv_swimmer + vec2(0,-1)*d);
vec2 uv2 = uv_swimmer - vec2(dx.x,dy.x)*0.4;
uv1 +=  - vec2(dx.x,dy.x);
ret = GetBlur2(uv1).z*0.6;
ret = mix(ret,vec3(1,-0.2,0.3)*vUv.y + vec3(1,1,-0.2)*(1-vUv.y),GetPixel(vUv - vec2(dx.x,dy.x)*0.4).z);

ret = mix(ret,1,GetBlur1(uv2).x);

ret = mix(ret,vec3(0.5,0,0.5)*vUv.x + vec3(0,1,1)*(1-vUv.x),GetPixel(uv_swimmer).x);

  fragColor = ret;
}
